scwin.onpageload = function () {
  const codeOptions = [{
    grpCd: "ZZ784",
    compID: "lc_logisticCenter"
  }];
  $c.data.setCommonCode($p, codeOptions);
};

// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
scwin.ondataload = function () {
  scwin.f_getManager("");
};
scwin.f_runExcel = async function () {
  let result = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
  if (!result) {
    return;
  }
  let sheetTitle = "경조용품 물류센터 담당자_" + scwin.currDate;
  const options = {
    fileName: sheetTitle + ".xlsx",
    sheetName: sheetTitle
  };
  $c.data.downloadGridViewExcel($p, gr_manager, options);
};
scwin.f_getManager = function (logisticCenter) {
  // SELECT 절 
  var param1 = "(SELECT CD_NM FROM TB_ZZ002 Z WHERE GRP_CD = 'ZZ784' AND Z.CD = A.FLTR_CD_1) as COL1 " + ",SUBSTR(A.CD_NM_ABBR, 0, 3) || ' ' || A.CD_ENG_NM_ABBR                       as COL2 " + ",A.CD_NM   					as COL3 " + ",A.CD_ENG_NM   				as COL4 " + ",A.FLTR_CD_1  				as COL5 " + ",'' 				as COL6 " + ",'' 				as COL7 " + ",'' 				as COL8 " + ",'' 				as COL9 " + ",'' 				as COL10 ";

  // 대상테이블 	
  var param2 = "TB_ZZ002 A";
  var param3 = "AND GRP_CD = 'ZZ786' AND USE_YN='1'";
  if (logisticCenter != "") {
    param3 = param3 + "AND A.FLTR_CD_1 = " + "'" + logisticCenter + "'";
  }
  var param4 = "COL1, COL2";
  dma_search.set("sysCd", "CommonEBC");
  dma_search.set("queryId", "dinymicQueryTest");
  dma_search.set("param1", param1);
  dma_search.set("param2", param2);
  dma_search.set("param3", param3);
  dma_search.set("param4", param4);
  $c.sbm.execute($p, sbm_manager);
};
scwin.lc_logisticCenter_onchange = function (info) {
  scwin.f_getManager(info.newValue);
};
scwin.sbm_manager_submitdone = function (e) {
  var rowCnt = ds_manager.getRowCount();
  spanTotal.setLabel(rowCnt);
  gr_manager.setFocusedCell(0, 0);
};
scwin.btn_Close_onclick = function (e) {
  $c.win.closePopup($p);
};
